=Hi, {{ $node["Parse HTML"].json.agent_name }}, below are the headline/descriptions for your latest listing.

HEADLINE: {{ $json.headline }}  

MLS DESCRIPTION: {{ $json.mls_description }}  

SOCIAL MEDIA POST: {{ $json.social_caption }}

parameters.jsCode:
const response = $input.first().json;
const text = response.content[0].text;

const headlineMatch = text.split('HEADLINE:')[1];
const mlsMatch = text.split('MLS_DESCRIPTION:')[1];
const socialMatch = text.split('SOCIAL_MEDIA_POST:')[1];

const headline = headlineMatch
  ? headlineMatch.split('MLS_DESCRIPTION:')[0].trim()
  : '';

const mls_description = mlsMatch
  ? mlsMatch.split('SOCIAL_MEDIA_POST:')[0].trim()
  : '';

const social_caption = socialMatch
  ? socialMatch.trim()
  : '';

return [{
  json: {
    headline,
    mls_description,
    social_caption
  }
}];

